import { Test, TestingModule } from '@nestjs/testing';
import { AuthService } from './../../auth.service';
import { RegisterUserService } from './../../services/register-user.service';
import { SignInService } from './../../services/sign-in.service';
import { SignInVerifyService } from './../../services/signInVerify.service';
import { SignOutService } from './../../services/sign-out.service';
import { ForgotPasswordService } from './../../services/forgot-password.service';
import { RefreshTokenService } from './../../services/refresh-token.service';
import { CreateUserDTO, ForgotPasswordDTO } from './../../../../libs';

describe('AuthService (integration)', () => {
  let authService: AuthService;

  let registerUserService: RegisterUserService;
  let signInService: SignInService;
  let signInVerifyService: SignInVerifyService;
  let signOutService: SignOutService;
  let forgotPasswordService: ForgotPasswordService;
  let refreshTokenService: RefreshTokenService;

  beforeEach(async () => {
    const module: TestingModule = await Test.createTestingModule({
      providers: [
        AuthService,
        {
          provide: RegisterUserService,
          useValue: { execute: jest.fn() },
        },
        {
          provide: SignInService,
          useValue: { execute: jest.fn() },
        },
        {
          provide: SignInVerifyService,
          useValue: { execute: jest.fn() },
        },
        {
          provide: SignOutService,
          useValue: { execute: jest.fn() },
        },
        {
          provide: ForgotPasswordService,
          useValue: { execute: jest.fn() },
        },
        {
          provide: RefreshTokenService,
          useValue: { execute: jest.fn() },
        },
      ],
    }).compile();

    authService = module.get<AuthService>(AuthService);

    registerUserService = module.get<RegisterUserService>(RegisterUserService);
    signInService = module.get<SignInService>(SignInService);
    signInVerifyService = module.get<SignInVerifyService>(SignInVerifyService);
    signOutService = module.get<SignOutService>(SignOutService);
    forgotPasswordService = module.get<ForgotPasswordService>(
      ForgotPasswordService,
    );
    refreshTokenService = module.get<RefreshTokenService>(RefreshTokenService);
  });

  it('deve estar definido', () => {
    expect(authService).toBeDefined();
  });

  it('deve delegar para RegisterUserService ao registrar', async () => {
    const dto: CreateUserDTO = {
      firstname: 'John',
      lastname: 'Doe',
      nickname: 'johndoe',
      email: 'test@test.com',
      password: '123456',
      role: 'USER',
    };

    const mockedUser: ReturnType<
      RegisterUserService['execute']
    > extends Promise<infer R>
      ? R
      : never = {
      id: 1,
      firstname: 'John',
      lastname: 'Doe',
      nickname: 'johndoe',
      email: 'test@test.com',
      role: 'USER',
      clientData: null,
    };

    jest
      .spyOn(registerUserService, 'execute')
      .mockResolvedValueOnce(mockedUser);

    const result = await registerUserService.execute(dto);

    expect(registerUserService['execute']).toHaveBeenCalledWith(dto);

    expect(result).toEqual(mockedUser);
  });

  it('deve delegar para SignInService ao logar', async () => {
    jest.spyOn(signInService, 'execute').mockResolvedValueOnce({
      accessToken: 'mocked-access-token',
      refreshToken: 'mocked-refresh-token',
      user: {
        id: 1,
        firstname: 'John',
        lastname: 'Doe',
        nickname: 'johndoe',
        email: 'mail@test.com',
        role: 'USER',
        clientData: null,
      },
    });

    const result = await authService.signIn('mail@test.com', '123');

    expect(jest.mocked(signInService['execute'])).toHaveBeenCalledWith(
      'mail@test.com',
      '123',
    );
    expect(result.accessToken).toBe('mocked-access-token');
    expect(result.user.email).toBe('mail@test.com');
  });

  it('deve delegar para SignInVerifyService ao verificar login', async () => {
    const spy = jest
      .spyOn(signInVerifyService, 'execute')
      .mockResolvedValueOnce({
        id: 1,
        firstname: 'John',
        lastname: 'Doe',
        nickname: 'johndoe',
        email: 'mail@test.com',
        role: 'USER',
        clientData: null,
      });

    const result = await authService.signInVerify('mail@test.com');

    expect(spy).toHaveBeenCalledWith('mail@test.com');
    expect(result.email).toBe('mail@test.com');
  });

  it('deve delegar para SignOutService ao deslogar', async () => {
    const spy = jest
      .spyOn(signOutService, 'execute')
      .mockResolvedValueOnce(undefined);

    const result = await authService.signOut(1);

    expect(spy).toHaveBeenCalledWith(1);
    expect(result).toBeUndefined();
  });

  it('deve delegar para ForgotPasswordService ao esquecer senha', async () => {
    const dto: ForgotPasswordDTO = { email: 'reset@test.com' };

    const spy = jest
      .spyOn(forgotPasswordService, 'execute')
      .mockResolvedValueOnce(undefined);

    const result = await authService.forgotPassword(dto);

    expect(spy).toHaveBeenCalledWith(dto);
    expect(result).toBeUndefined();
  });

  it('deve delegar para RefreshTokenService ao renovar token', async () => {
    const spy = jest
      .spyOn(refreshTokenService, 'execute')
      .mockResolvedValueOnce({
        accessToken: 'new-access-token',
        refreshToken: 'new-refresh-token',
      });

    const result = await authService.refreshToken('fake-token');

    expect(spy).toHaveBeenCalledWith('fake-token');
    expect(result).toEqual({
      accessToken: 'new-access-token',
      refreshToken: 'new-refresh-token',
    });
  });
});
